 using System.ComponentModel;
 using System.Net;
 using System.Text.Json;
 using Microsoft.Extensions.AI;
 using OpenAI;

 // --- Tool implementations -------------------------------------------------

 /// <summary>Stores notes the agent takes while researching.</summary>
 static class Notepad
 {
     private static readonly List<string> _notes = [];

     [Description("Save a research note. Use this to record key findings from search results.")]
     public static string SaveNote(
         [Description("The note text to save")] string note)
     {
         _notes.Add(note);
         return $"Note #{_notes.Count} saved.";
     }

     [Description("Retrieve all saved research notes.")]
     public static string GetNotes()
     {
         if (_notes.Count == 0)
             return "No notes saved yet.";

         return string.Join("\n", _notes.Select((n, i) => $"[{i + 1}] {n}"));
     }
 }

 /// <summary>Provides web-search capability via the Brave Search API (free tier).</summary>
 static class WebSearch
 {
     private static readonly HttpClient Http = new();

     [Description("Search the web for information on a query. Returns a list of result titles, URLs, and snippets.")]
     public static async Task<string> Search(
         [Description("The search query string")] string query,
         [Description("Max number of results to return (default 5)")] int count = 5)
     {
         // Use Brave Search API if a key is available; otherwise fall back to
         // a lightweight DuckDuckGo HTML scrape so the app works out-of-the-box.
         var braveKey = Environment.GetEnvironmentVariable("BRAVE_SEARCH_API_KEY");
         if (!string.IsNullOrWhiteSpace(braveKey))
             return await BraveSearch(query, count, braveKey);

         return await DuckDuckGoFallback(query, count);
     }

     private static async Task<string> BraveSearch(string query, int count, string apiKey)
     {
         var url = $"https://api.search.brave.com/res/v1/web/search?q={Uri.EscapeDataString(query)}&count={count}";
         var request = new HttpRequestMessage(HttpMethod.Get, url);
         request.Headers.Add("Accept", "application/json");
         request.Headers.Add("X-Subscription-Token", apiKey);

         var response = await Http.SendAsync(request);
         response.EnsureSuccessStatusCode();
         var json = await response.Content.ReadAsStringAsync();

         using var doc = JsonDocument.Parse(json);
         var results = doc.RootElement.GetProperty("web").GetProperty("results");

         var entries = new List<string>();
         foreach (var r in results.EnumerateArray().Take(count))
         {
             var title = r.GetProperty("title").GetString();
             var link = r.GetProperty("url").GetString();
             var snippet = r.TryGetProperty("description", out var d) ? d.GetString() : "";
             entries.Add($"- {title}\n  {link}\n  {snippet}");
         }

         return entries.Count == 0
             ? "No results found."
             : string.Join("\n\n", entries);
     }

     private static async Task<string> DuckDuckGoFallback(string query, int count)
     {
         var url = $"https://html.duckduckgo.com/html/?q={Uri.EscapeDataString(query)}";
         var request = new HttpRequestMessage(HttpMethod.Get, url);
         request.Headers.Add("User-Agent", "ResearchAgent/1.0");

         var response = await Http.SendAsync(request);
         response.EnsureSuccessStatusCode();
         var html = await response.Content.ReadAsStringAsync();

         // Lightweight parse of DuckDuckGo HTML results
         var entries = new List<string>();
         var snippetTag = "class=\"result__snippet\"";
         var titleTag = "class=\"result__a\"";
         var pos = 0;
         while (entries.Count < count && pos < html.Length)
         {
             var titleStart = html.IndexOf(titleTag, pos, StringComparison.Ordinal);
             if (titleStart < 0) break;

             var title = ExtractTagContent(html, titleStart);
             var href = ExtractHref(html, titleStart);

             var snippetStart = html.IndexOf(snippetTag, titleStart, StringComparison.Ordinal);
             var snippet = snippetStart >= 0 ? ExtractTagContent(html, snippetStart) : "";

             entries.Add($"- {WebUtility.HtmlDecode(title)}\n  {href}\n  {WebUtility.HtmlDecode(snippet)}");
             pos = snippetStart >= 0 ? snippetStart + 1 : titleStart + 1;
         }

         return entries.Count == 0
             ? "No results found."
             : string.Join("\n\n", entries);
     }

     private static string ExtractTagContent(string html, int attrPos)
     {
         var gt = html.IndexOf('>', attrPos);
         if (gt < 0) return "";
         var close = html.IndexOf('<', gt);
         if (close < 0) return "";
         return html[( gt + 1)..close].Trim();
     }

     private static string ExtractHref(string html, int attrPos)
     {
         // Walk backwards from attrPos to find the <a tag, then find href
         var tagStart = html.LastIndexOf("<a ", attrPos, Math.Min(attrPos, 500), StringComparison.Ordinal);
         if (tagStart < 0) return "";
         var hrefStart = html.IndexOf("href=\"", tagStart, StringComparison.Ordinal);
         if (hrefStart < 0 || hrefStart > attrPos) return "";
         hrefStart += 6;
         var hrefEnd = html.IndexOf('"', hrefStart);
         if (hrefEnd < 0) return "";
         var raw = html[hrefStart..hrefEnd];
         // DuckDuckGo wraps URLs in a redirect; extract the actual URL
         if (raw.Contains("uddg="))
         {
             var uddg = raw.IndexOf("uddg=", StringComparison.Ordinal) + 5;
             var amp = raw.IndexOf('&', uddg);
             raw = amp > 0 ? raw[uddg..amp] : raw[uddg..];
             raw = Uri.UnescapeDataString(raw);
         }
         return raw;
